static TRAIT_REPLY_COUNTER: AtomicU64 = AtomicU64::new(1);

type TraitReplyChannel = tokio::sync::oneshot::Sender<std::result::Result<String, String>>;

static TRAIT_REPLY_CHANNELS: std::sync::LazyLock<Mutex<HashMap<u64, TraitReplyChannel>>> =
    std::sync::LazyLock::new(|| Mutex::new(HashMap::new()));

/// Extract content from a single bytes or URI input.
#[rustler::nif(schedule = "DirtyCpu")]
pub fn extract_async(input: Option<String>, config: Option<String>) -> Result<ExtractionResult, String> {
    let input_core: Option<xberg::ExtractInput> = input
        .map(|s| serde_json::from_str::<xberg::ExtractInput>(&s))
        .transpose()
        .map_err(|e| e.to_string())?;
    let config_core: Option<xberg::ExtractionConfig> = config
        .map(|s| serde_json::from_str::<xberg::ExtractionConfig>(&s))
        .transpose()
        .map_err(|e| e.to_string())?;
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        std::thread::Builder::new()
            .stack_size(32 * 1024 * 1024)
            .spawn(move || {
                let rt = tokio::runtime::Runtime::new().map_err(|e| e.to_string())?;
                let result = rt
                    .block_on(async {
                        xberg::extract(
                            input_core.unwrap_or_default(),
                            config_core.as_ref().unwrap_or(&Default::default()),
                        )
                        .await
                    })
                    .map_err(|e| e.to_string())?;
                Ok(result.into())
            })
            .map_err(|e| e.to_string())?
            .join()
            .map_err(|_| "thread panicked".to_string())
    }));
    match result {
        Ok(inner_result) => inner_result?,
        Err(_) => Err("thread panic during async operation".to_string()),
    }
}

/// Extract content from multiple bytes or URI inputs.
#[rustler::nif(schedule = "DirtyCpu")]
pub fn extract_batch_async(inputs: Option<String>, config: Option<String>) -> Result<ExtractionResult, String> {
    let inputs_core: Vec<xberg::ExtractInput> = inputs
        .map(|s| serde_json::from_str::<Vec<xberg::ExtractInput>>(&s).map_err(|e| e.to_string()))
        .transpose()?
        .unwrap_or_default();
    let config_core: Option<xberg::ExtractionConfig> = config
        .map(|s| serde_json::from_str::<xberg::ExtractionConfig>(&s))
        .transpose()
        .map_err(|e| e.to_string())?;
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        std::thread::Builder::new()
            .stack_size(32 * 1024 * 1024)
            .spawn(move || {
                let rt = tokio::runtime::Runtime::new().map_err(|e| e.to_string())?;
                let result = rt
                    .block_on(async {
                        xberg::extract_batch(inputs_core, config_core.as_ref().unwrap_or(&Default::default())).await
                    })
                    .map_err(|e| e.to_string())?;
                Ok(result.into())
            })
            .map_err(|e| e.to_string())?
            .join()
            .map_err(|_| "thread panicked".to_string())
    }));
    match result {
        Ok(inner_result) => inner_result?,
        Err(_) => Err("thread panic during async operation".to_string()),
    }
}

#[cfg(feature = "url-ingestion")]
/// Discover all pages and sitemaps reachable from `uri` without extracting document content.
///
/// Builds a `crawlberg::CrawlEngine` from `config.crawl`, calls
/// `CrawlEngine::map`, and returns the set of discovered URLs as a
/// `crawlberg::MapResult` (re-exported as `MapResult`).
///
/// Use this when you need the URL inventory of a site before committing to
/// full document extraction — e.g. to build a crawl queue or validate scope.
///
/// # Errors
///
/// Returns `Validation` if the crawl configuration fails
/// validation or if the map operation itself fails.
#[rustler::nif(schedule = "DirtyCpu")]
pub fn map_url_async(uri: String, config: Option<String>) -> Result<MapResult, String> {
    let config_core: Option<xberg::UrlExtractionConfig> = config
        .map(|s| serde_json::from_str::<xberg::UrlExtractionConfig>(&s))
        .transpose()
        .map_err(|e| e.to_string())?;
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        std::thread::Builder::new()
            .stack_size(32 * 1024 * 1024)
            .spawn(move || {
                let rt = tokio::runtime::Runtime::new().map_err(|e| e.to_string())?;
                let result = rt
                    .block_on(async { xberg::map_url(&uri, config_core.as_ref().unwrap_or(&Default::default())).await })
                    .map_err(|e| e.to_string())?;
                Ok(result.into())
            })
            .map_err(|e| e.to_string())?
            .join()
            .map_err(|_| "thread panicked".to_string())
    }));
    match result {
        Ok(inner_result) => inner_result?,
        Err(_) => Err("thread panic during async operation".to_string()),
    }
}

