#[rustler::nif]
pub fn registry_is_empty(resource: rustler::ResourceArc<Registry>) -> bool {
    resource.inner.read().unwrap_or_else(|e| e.into_inner()).is_empty()
}

/// Read raw sample bytes for `<preset_id>` from
/// `library/<id>/samples/<name>`. Returns `None` when the file is absent.
#[rustler::nif]
pub fn registry_sample_bytes(
    resource: rustler::ResourceArc<Registry>,
    preset_id: String,
    name: String,
) -> Option<Vec<u8>> {
    resource
        .inner
        .read()
        .unwrap_or_else(|e| e.into_inner())
        .sample_bytes(&preset_id, &name)
        .map(|v| v.into())
}

/// Load additional preset files from a runtime directory and insert them
/// into this registry.
///
/// Reads every `*.json` file directly under `dir` (non-recursive),
/// validates each against the meta-schema, and inserts it. Files that fail
/// validation are rejected — the error is returned immediately and the
/// registry is left in a partially-updated state. Existing entries with the
/// same id are overwritten.
///
/// Returns the number of presets successfully loaded from `dir`.
///
/// # Use case
///
/// This is the injection point for downstream catalogs that add curated
/// presets on top of the single embedded OSS preset.
#[rustler::nif]
pub fn registry_extend_from_dir(resource: rustler::ResourceArc<Registry>, dir: String) -> Result<usize, String> {
    let result = resource
        .inner
        .write()
        .unwrap_or_else(|e| e.into_inner())
        .extend_from_dir(&std::path::PathBuf::from(dir))
        .map_err(|e| e.to_string())?;
    Ok(result)
}

/// Sets a custom cache directory for model files.
///
/// # Arguments
///
/// * `path` - Path to cache directory
///
/// # Examples
///
/// ```no_run
/// use xberg::PaddleOcrConfig;
/// use std::path::PathBuf;
///
/// let config = PaddleOcrConfig::new("en")
///     .with_cache_dir(PathBuf::from("/tmp/paddle-cache"));
/// ```
#[rustler::nif]
pub fn paddleocrconfig_with_cache_dir(obj: PaddleOcrConfig, path: String) -> PaddleOcrConfig {
    xberg::PaddleOcrConfig::from(obj)
        .with_cache_dir(std::path::PathBuf::from(path))
        .into()
}

