#[rustler::nif]
pub fn set_env(key: String, value: String) -> bool {
    // SAFETY: called once from the e2e harness during setup before extraction
    // NIFs run on other scheduler threads, so no concurrent env access.
    unsafe {
        std::env::set_var(&key, &value);
    }
    true
}

fn on_load(env: rustler::Env, _info: rustler::Term) -> bool {
    env.register::<TokenCounter>()
        .expect("Failed to register resource type TokenCounter");
    env.register::<MetaSchema>()
        .expect("Failed to register resource type MetaSchema");
    env.register::<Registry>()
        .expect("Failed to register resource type Registry");
    true
}

rustler::init!("Elixir.Xberg.Native", load = on_load);
